// Planning Problem Definition
BEGIN
 // State representation: set of propositions
 INITIAL_STATE = {At(Home), ¬At(Office), Has(Milk, False), Has(Bread, False)}
 GOAL_STATE = {At(Office), Has(Milk, True), Has(Bread, True)}

 // Action definition with preconditions and effects
 ACTION Buy(Item):
 PRECONDITIONS: {At(Store), Has(Item, False)}
 EFFECTS: {Add(Has(Item, True)), Delete(Has(Item, False))}

 ACTION Drive(From, To):
 PRECONDITIONS: {At(From)}
 EFFECTS: {Add(At(To)), Delete(At(From))}

 PLANNING_PROBLEM = (INITIAL_STATE, GOAL_STATE, ACTIONS)
END
